-- ----------------------------------------------------------------------------
-- vw_transaction_types: Table: TransactionTypes
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_transaction_types WITH (security_invoker = ON) AS
SELECT
  t.transaction_type_id,                                                        -- Type identifier (Purchase, Sale, Adjustment).
  calc_transaction_types_name(t.transaction_type_id) AS name,                   -- Display name, derived from TransactionTypeId.
  t.description                                                                 -- What this transaction type represents.
FROM transaction_types t;

-- ----------------------------------------------------------------------------
-- vw_products: Table: Products
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_products WITH (security_invoker = ON) AS
SELECT
  t.product_id,                                                                 -- Product identifier (SKU or natural key).
  calc_products_name(t.product_id) AS name,                                     -- Display name, derived from ProductId.
  t.unit_price,                                                                 -- Price per unit in dollars.
  t.reorder_level,                                                              -- Minimum quantity before reorder is recommended.
  calc_products_current_quantity(t.product_id) AS current_quantity,             -- Running total of all transaction quantities for this product.
  calc_products_is_low_stock(t.product_id) AS is_low_stock,                     -- True if current quantity falls below the reorder level.
  calc_products_reorder_status(t.product_id) AS reorder_status                  -- Urgent reorder message if stock is low, otherwise in stock status.
FROM products t;

-- ----------------------------------------------------------------------------
-- vw_transactions: Table: Transactions
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_transactions WITH (security_invoker = ON) AS
SELECT
  t.transaction_id,                                                             -- Unique transaction identifier.
  calc_transactions_name(t.transaction_id) AS name,                             -- Display name, derived from TransactionId.
  t.product,                                                                    -- Reference to the product being adjusted.
  calc_transactions_product_name(t.transaction_id) AS product_name,             -- Product display name via lookup.
  calc_transactions_product_unit_price(t.transaction_id) AS product_unit_price, -- Product unit price via lookup, for calculating transaction amount.
  t.transaction_type,                                                           -- Type of transaction (Purchase, Sale, Adjustment).
  calc_transactions_transaction_type_name(t.transaction_id) AS transaction_type_name,-- Transaction type display name via lookup.
  t.quantity,                                                                   -- Quantity adjustment (positive for purchases/returns, negative for sales).
  calc_transactions_amount(t.transaction_id) AS amount,                         -- Transaction value = Quantity × UnitPrice.
  t.transaction_date,                                                           -- When the transaction occurred.
  t.notes                                                                       -- Optional notes about this transaction.
FROM transactions t;

